"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[89883],{79066(e,t,n){n.r(t),n.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>h,frontMatter:()=>i,metadata:()=>s,toc:()=>l});let s=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments and IFRS 16 Leases/lessor-forgiveness-of-lease-payments-c873b0bd71","title":"Lessor Forgiveness of Lease Payments (IFRS 9 and IFRS 16)","description":"October 2022","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments and IFRS 16 Leases/Lessor Forgiveness of Lease Payments (IFRS 9 and IFRS 16).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments and IFRS 16 Leases","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-and-ifr-f215bc1791/lessor-forgiveness-of-lease-payments-c873b0bd71","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-and-ifr-f215bc1791/lessor-forgiveness-of-lease-payments-c873b0bd71","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"lessor-forgiveness-of-lease-payments-c873b0bd71","title":"Lessor Forgiveness of Lease Payments (IFRS 9 and IFRS 16)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-and-ifr-f215bc1791/lessor-forgiveness-of-lease-payments-c873b0bd71","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Physical Settlement of Contracts to Buy or Sell a Non-financial Item (IFRS 9)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/physical-settlement-of-contracts-to--8e19b89d27"},"next":{"title":"TLTRO III Transactions (IFRS 9 and IAS 20)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-and-ias-20-74020d5e15/tltro-iii-transactions-ifrs-9-and-ia-e175efc16b"}}');var a=n(74848),o=n(28453);let i={id:"lessor-forgiveness-of-lease-payments-c873b0bd71",title:"Lessor Forgiveness of Lease Payments (IFRS 9 and IFRS 16)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-and-ifr-f215bc1791/lessor-forgiveness-of-lease-payments-c873b0bd71",sidebar_position:1},r,c={},l=[];function d(e){let t={p:"p",strong:"strong",...(0,o.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.p,{children:"October 2022"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about a lessor\u2019s application of IFRS 9 and IFRS 16 in accounting for a particular rent concession. The rent concession is one for which the only\nchange to the lease contract is the lessor\u2019s forgiveness of lease payments due from the lessee under that contract."}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"The fact pattern"}),"\nThe request described a rent concession agreed by a lessor and a lessee on the date the rent concession is granted. The rent concession changes the original terms and\nconditions of a lease contract classified by the lessor\u2014applying IFRS 16\u2014as an operating lease. The lessor legally releases the lessee from its obligation to make specifically\nidentified lease payments:"]}),"\n",(0,a.jsx)(t.p,{children:"a. some of these lease payments are amounts contractually due but not paid. Paragraph AG9 of IAS 32 states that \u2018a lessor does not regard an operating lease as a financial instrument, except as regards individual payments currently due and payable by the lessee\u2019. Therefore, the lessor has recognised these amounts as an operating lease receivable. Applying paragraph 81 of IFRS 16, the lessor has also recognised the amounts as income.\nb. some of these lease payments are not yet contractually due. No other changes are made to the lease contract, nor are there any other negotiations between the lessor and the lessee that might affect the accounting for the rent concession. Before the date the rent concession is granted, the lessor applies the expected credit loss model in IFRS 9 to the operating lease receivable."}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"The question"}),"\nThe request asked:\na. how the lessor applies the expected credit loss model in IFRS 9 to the operating lease receivable before the rent concession is granted if it expects to forgive payments due from the lessee under the lease contract; and\nb. whether the lessor applies the derecognition requirements in IFRS 9 or the lease modification requirements in IFRS 16 in accounting for the rent concession."]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"Applying the expected credit loss model in IFRS 9 to the operating lease receivable"}),"\nParagraph 2.1(b)(i) of IFRS 9 states that \u2018operating lease receivables recognised by a lessor are subject to the derecognition and impairment requirements\u2019 in IFRS 9. Therefore, a\nlessor is required to apply the impairment requirements in IFRS 9 to the gross carrying amount of an operating lease receivable from the date on which it recognises that receivable, taking into account applicable derecognition requirements in IFRS 9."]}),"\n",(0,a.jsx)(t.p,{children:"IFRS 9 defines credit loss as \u2018the difference between all contractual cash flows that are due to an entity in accordance with the contract and all the cash flows that the entity\nexpects to receive (ie all cash shortfalls)\u2026\u2019. Paragraph 5.5.17 of IFRS 9 states that \u2018an entity shall measure expected credit losses \u2026 in a way that reflects (a) an unbiased and\nprobability-weighted amount that is determined by evaluating a range of possible outcomes; (b) the time value of money; and (c) reasonable and supportable information\nthat is available without undue cost or effort at the reporting date about past events, current conditions and forecasts of future economic conditions\u2019."}),"\n",(0,a.jsx)(t.p,{children:"Consequently, in the fact pattern described in the request, the lessor applies the impairment requirements in IFRS 9 to the operating lease receivable. The lessor estimates\nexpected credit losses on the operating lease receivable by measuring any credit loss to reflect \u2018all cash shortfalls\u2019. These shortfalls are the difference between:"}),"\n",(0,a.jsx)(t.p,{children:"a. all contractual cash flows due to the lessor in accordance with the lease contract (and included in the gross carrying amount of the operating lease receivable); and\nb. all the cash flows the lessor expects to receive, determined using \u2018reasonable and supportable information\u2019 about \u2018past events, current conditions and forecasts of\nfuture economic conditions\u2019."}),"\n",(0,a.jsx)(t.p,{children:"Therefore, the Committee concluded that, before the rent concession is granted, the lessor measures expected credit losses on the operating lease receivable in a way that\nreflects \u2018an unbiased and probability-weighted amount \u2026\u2019, \u2018the time value of money\u2019, and \u2018reasonable and supportable information \u2026\u2019 (as required by paragraph 5.5.17 of\nIFRS 9). This measurement of expected credit losses includes the lessor considering its expectations of forgiving lease payments recognised as part of that receivable."}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"Accounting for the rent concession\u2014IFRS 9 and IFRS 16"}),"\nApplying the derecognition requirements in IFRS 9 to the operating lease receivable Paragraph 2.1(b)(i) of IFRS 9 states that operating lease receivables recognised by a lessor\nare subject to the derecognition requirements in IFRS 9. Consequently, on granting the rent concession, the lessor considers whether the requirements for derecognition in\nparagraph 3.2.3 of IFRS 9 are met."]}),"\n",(0,a.jsx)(t.p,{children:"In the rent concession described in the request, the lessor legally releases the lessee from its obligation to make specifically identified lease payments, some of which the lessor has\nrecognised as an operating lease receivable. Accordingly, on granting the rent concession, the lessor concludes that the requirements in paragraph 3.2.3(a) of IFRS 9 have been met \u2014that is, its contractual rights to the cash flows from the operating lease receivable expire\u2014because it has agreed to legally release the lessee from its obligation and thus has\ngiven up its contractual rights to those specifically identified cash flows. Therefore, on the date the rent concession is granted, the lessor remeasures expected credit losses on\nthe operating lease receivable (and recognises any change to the expected credit loss allowance in profit or loss) and derecognises the operating lease receivable (and associated expected credit loss allowance)."}),"\n",(0,a.jsx)(t.p,{children:"Applying the lease modification requirements in IFRS 16 to future lease payments under the lease"}),"\n",(0,a.jsx)(t.p,{children:"The rent concession described in the request meets the definition of a lease modification in IFRS 16. The rent concession is \u2018a change in \u2026 the consideration for a lease \u2026 that was\nnot part of the original terms and conditions of the lease\u2019. Therefore, the lessor applies paragraph 87 of IFRS 16 and accounts for the modified lease as a new lease from the date\nthe rent concession is granted."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 87 of IFRS 16 requires a lessor to consider any prepaid or accrued lease payments relating to the original lease as part of the lease payments for the new lease. The Committee observed that lease payments contractually due from the lessee that the lessor has recognised as an operating lease receivable (to which the derecognition and\nimpairment requirements in IFRS 9 apply) are not accrued lease payments. Consequently, neither those lease payments nor their forgiveness are considered\u2014applying paragraph 87 of IFRS 16\u2014as part of the lease payments for the new lease."}),"\n",(0,a.jsx)(t.p,{children:"In accounting for the modified lease as a new lease, a lessor applies paragraph 81 of IFRS 16 and recognises the lease payments (including any prepaid or accrued lease\npayments relating to the original lease) as income on either a straight-line basis or another systematic basis."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the lessor accounts for the rent concession described in the request on the date it is granted by applying: (a) the derecognition requirements in\nIFRS 9 to forgiven lease payments that the lessor has recognised as an operating lease receivable; and (b) the lease modification requirements in IFRS 16 to forgiven lease\npayments that the lessor has not recognised as an operating lease receivable."}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"Conclusion"}),"\nThe Committee concluded that the principles and requirements in IFRS Accounting Standards provide an adequate basis for a lessor to determine how to apply the expected\ncredit loss model in IFRS 9 to an operating lease receivable and account for the rent concession described in the request. Consequently, the Committee decided not to add a\nstandard-setting project to the work plan."]})]})}function h(e={}){let{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},28453(e,t,n){n.d(t,{R:()=>i,x:()=>r});var s=n(96540);let a={},o=s.createContext(a);function i(e){let t=s.useContext(o);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:i(e.components),s.createElement(o.Provider,{value:t},e.children)}}}]);